class Solution:
    def canTransform(self, start: str, result: str) -> bool:
        i, j = 0, 0
        while i < len(start) and j < len(result):
            if start[i] == 'L' and result[j] == 'L':
                i += 1
                j += 1
            elif start[i] == 'R' and result[j] == 'R':
                i += 1
                j += 1
            elif start[i] == 'X' and result[j] == 'L':
                while i < len(start) and start[i] == 'X':
                    i += 1
                if i == len(start):
                    return False
            elif start[i] == 'X' and result[j] == 'R':
                while j < len(result) and result[j] == 'R':
                    j += 1
                if j == len(result):
                    return False
            else:
                return False
            i += 1
            j += 1
        return i == len(start) and j == len(result)
